{
  "name": "Georgia State Health Insurance Assistance Program (Georgia SHIP)",
  "eligibility": {
    "age": null,
    "income_limits": "No income or asset limits; open to all Medicare beneficiaries, their families, and caregivers, including those with limited incomes, under age 65 with disabilities, or dually eligible for Medicare and Medicaid[2][3][8]",
    "asset_limits": "No asset limits or tests apply; no specification of what counts or is exempt[2][3]",
    "other_requirements": ["Must be a Medicare beneficiary or caregiver/family member of one", "Georgia resident (implied for state program access)", "Services focus on Medicare-related issues, but no incarceration or citizenship requirements specified for SHIP itself[1][2]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free, unbiased one-on-one counseling and assistance on Medicare (Parts A, B, C, D), Medigap, Medicaid, prescription drug programs, long-term care insurance, claims/billing resolution, appeals, fraud reporting via SMP, enrollment in plans and financial assistance programs (e.g., Medicare Savings Programs like QMB/SLMB/QI, Extra Help), information/referrals, public education presentations, and outreach events; no fixed dollar amounts or hours, provided via phone, face-to-face, or community sessions[2][3][5][6][8][10]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 1-866-552-4464 (select Option 4)[7][8]", "Website: https://aging.georgia.gov/georgia-ship[7][8][10]", "Local in-person or email via regional providers (e.g., 706-549-4850 or lplatter@accaging.org for ACCA area)[5]", "Request counseling sessions, presentations, or referrals directly; no formal application form required for counseling"],
    "processing_time": "Immediate assistance available via phone or sessions; no specified processing timeline as it's counseling-based, not enrollment with approval wait[2][8]",
    "waitlist": null,
    "forms": ["No specific forms required for SHIP counseling; may assist with Medicare/Medicaid/Extra Help applications during sessions"],
    "documents": ["Medicare card, Medicare Summary Notices, Explanation of Benefits, medical bills, insurance details for review/appeals; not mandatory for initial contact[8][10]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available across Georgia",
    "regional_variations": "Delivered through local partners like Area Agencies on Aging (e.g., ACCA at 706-549-4850); same core services statewide with local offices for face-to-face access[2][5]",
    "offices_or_providers": ["Administered by Georgia Department of Human Services Division of Aging Services; local contacts via 1-866-552-4464[2][5][8]"]
  },
  "official_source": "https://aging.georgia.gov/georgia-ship",
  "gotchas": ["Not a healthcare or financial aid program itself—provides counseling only, does not pay bills or provide direct services; not affiliated with insurance companies and does not sell plans[8][10]", "People may confuse with direct enrollment programs; must be Medicare-related issue[2]", "Volunteer-based, so availability may depend on local counselor schedules[5][9]", "Assists with low-income programs like SLMB/QI but has no eligibility test itself[3][4][6]"],
  "data_shape_notes": "no income test; counseling-only service with volunteer/local delivery model; prioritizes Medicare beneficiaries without barriers"
}

{
  "name": "Legal Assistance for Older Georgians",
  "eligibility": {
    "age": 60,
    "income_limits": "No statewide income limits set by ELAP; some providers like Georgia Legal Services Program (GLSP) use generally not more than 200% of federal poverty level, but ELAP standards require no income requirements[1][2][3]",
    "asset_limits": "No asset limits mentioned or required[1][3]",
    "other_requirements": ["Live in Georgia", "Legal problem is civil (not criminal)", "Legal problem is one ELAP handles (e.g., abuse/neglect/exploitation, age discrimination, accessing health care, debt collection, housing, consumer fraud, Medicare fraud, advance directives, powers of attorney)", "Circumstances put life or well-being at risk or in danger[1]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free legal help including advice, brief services, representation by attorneys/paralegals/law firms in priority civil cases such as abuse/neglect/exploitation, age discrimination, accessing health care, debt collection, housing, consumer fraud, Medicare fraud, advance directives, durable powers of attorney[1][4][8]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Contact local ELAP law firm by county (phone numbers listed by county on aging.georgia.gov/tools-resources/elderly-legal-assistance-program)", "Georgia Senior Legal Hotline: (404) 389-9992 (Mon-Thu 9am-2pm, phone advice/brief service/referrals)", "Aging and Disability Resource Connection: 866-552-4464 or aging.georgia.gov/adrc (if need more than legal help)", "Regional examples: Coastal area Georgia Legal Services 1-888-220-8399[1][4][8]", "Atlanta Legal Aid: (404) 389-9992, atlantalegalaid.org[7][8]"],
    "processing_time": "Not specified",
    "waitlist": null,
    "forms": ["No specific forms named; apply by contacting provider directly or online eligibility check for GLSP[2]"],
    "documents": ["Services often over phone; prepare details of legal issue. No specific documents listed[8]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Available in most Georgia counties; GLSP excludes Clayton, Cobb, DeKalb, Fulton, Gwinnett counties[1][2]",
    "regional_variations": "Delivered through network of local law firms/agencies by county; different providers and contact numbers per county/region (e.g., Coastal Regional Commission refers to Georgia Legal Services)[1][4]",
    "offices_or_providers": ["County-specific law firms listed on aging.georgia.gov/tools-resources/elderly-legal-assistance-program", "Georgia Legal Services Program (most counties outside Metro-Atlanta)", "Atlanta Legal Aid (Atlanta area)", "Georgia Senior Legal Hotline (statewide phone)[1][2][7][8]"]
  },
  "official_source": "https://aging.georgia.gov/tools-resources/elderly-legal-assistance-program",
  "gotchas": ["Must contact specific law firm for your county, not a central office", "Only civil non-criminal cases ELAP handles; problem must threaten life/well-being", "No income test statewide but some providers apply one", "Excludes certain Metro-Atlanta counties for some providers like GLSP", "If need non-legal help too, use ADRC instead of direct law firm[1][2]"],
  "data_shape_notes": "No income or asset test required statewide per standards; county-specific providers and contacts; priority on cases threatening independence/well-being; Metro-Atlanta counties may have different access[1][3]"
}

{
  "name": "Long-Term Care Ombudsman Program",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; available to all residents and anyone with concerns about long-term care facilities[2][3][4]",
    "asset_limits": "No asset limits; no financial eligibility requirements[4]",
    "other_requirements": ["Resident of a long-term care facility in Georgia (nursing homes, personal care homes, assisted living, community living arrangements, or ICF/IDDs), or family/friend with a concern on their behalf. Requires resident permission for intervention[2][3]"]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Investigates and resolves complaints; advocates for resident rights; provides information on long-term care; routine facility visits and monitoring; education for residents, families, staff, and communities; assistance with transfers/discharges, access to benefits; no charge for services[1][2][3][4][5]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 1-866-552-4464 (select option 5); Website: https://www.georgiaombudsman.org (locate community ombudsman by county); Local offices (e.g., State Ombudsman: 888/454-5826, Sowega COA for south GA, ACCA at 706.549-4850 for east GA); Email state ombudsman: bakurtz@dhr.state.ga.us[2][3][4][5]"],
    "processing_time": "Not specified; focuses on informal resolution, no formal processing timeline mentioned[2][3]",
    "waitlist": null,
    "forms": ["No specific forms required; contact directly to report concerns or request assistance[2][3][4]"],
    "documents": ["No documents needed to contact; resident permission may be required for intervention. Provide details of concern, facility name, and resident info[2][3]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Services cover all Georgia counties via 13 community programs contracted through Area Agencies on Aging[1][2][4][5]",
    "regional_variations": "Delivered regionally by different providers (e.g., Sowega COA for 48 southern counties, ACCA for 25 eastern counties including Athens-Augusta-Gwinnett); local contacts handle services with statewide oversight[1][2][4][5]",
    "offices_or_providers": ["Office of the State Ombudsman (Atlanta: 2 Peachtree St NW Suite 9-231); Community programs via georgiaombudsman.org county locator; Sowega COA (south GA); ACCA (east GA)[1][2][4][5]"]
  },
  "official_source": "https://aging.georgia.gov/programs-and-services/long-term-care-ombudsman-program or https://www.georgiaombudsman.org[3][2]",
  "gotchas": ["Not a healthcare or financial aid program—purely advocacy and complaint resolution; requires resident permission to intervene; families can contact on behalf of loved one but ombudsman prioritizes resident's wishes; not for pre-admission qualification—services for those already in facilities; people miss that it's free and confidential with no eligibility barriers[1][2][3][4][5]"],
  "data_shape_notes": "no income test; statewide advocacy via 13 regional community providers; resident permission required; free service focused on rights protection and complaint resolution in facilities, not admission or direct care"
}
